package pe.edu.utp.tmo.security; import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.IOException; import java.security.SecureRandom; import java.util.HexFormat; import org.slf4j.MDC; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter; @Component public class RequestTraceFilter extends OncePerRequestFilter{ private final SecureRandom r=new SecureRandom(); protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain) throws ServletException,IOException{byte[] b=new byte[8]; r.nextBytes(b); String id=HexFormat.of().formatHex(b); MDC.put("traceId",id); res.setHeader("X-Trace-Id",id); try{chain.doFilter(req,res);}finally{MDC.remove("traceId");}} }